package com.example.enterpriseapp.service;

import com.example.enterpriseapp.model.User;
import com.example.enterpriseapp.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.Optional;

@Service
public class UserService {

    private final UserRepository userRepository;

    @Autowired
    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public User createUser(User user) {
        if (userRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("User with email '" + user.getEmail() + "' already exists.");
        }
        if (userRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("User with username '" + user.getUsername() + "' already exists.");
        }
        return userRepository.save(user);
    }

    @Transactional(readOnly = true)
    public Optional<User> getUserById(Long id) {
        return userRepository.findById(id);
    }

    @Transactional(readOnly = true)
    public Optional<User> getUserByEmail(String email) {
        return userRepository.findByEmail(email);
    }

    @Transactional(readOnly = true)
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    @Transactional
    public User updateUser(Long id, User userDetails) {
        return userRepository.findById(id)
                .map(existingUser -> {
                    // Check if email or username is changed and if new values already exist for other users
                    if (!userDetails.getEmail().equals(existingUser.getEmail()) && userRepository.existsByEmail(userDetails.getEmail())) {
                        throw new IllegalArgumentException("Email '" + userDetails.getEmail() + "' is already taken by another user.");
                    }
                    if (!userDetails.getUsername().equals(existingUser.getUsername()) && userRepository.existsByUsername(userDetails.getUsername())) {
                        throw new IllegalArgumentException("Username '" + userDetails.getUsername() + "' is already taken by another user.");
                    }

                    existingUser.setUsername(userDetails.getUsername());
                    existingUser.setEmail(userDetails.getEmail());
                    existingUser.setFirstName(userDetails.getFirstName());
                    existingUser.setLastName(userDetails.getLastName());
                    return userRepository.save(existingUser);
                }).orElseThrow(() -> new IllegalArgumentException("User not found with id " + id));
    }

    @Transactional
    public void deleteUser(Long id) {
        if (!userRepository.existsById(id)) {
            throw new IllegalArgumentException("User not found with id " + id);
        }
        userRepository.deleteById(id);
    }

    /**
     * Example of a complex transactional operation that involves multiple steps.
     * If any part of this method fails, the entire transaction will be rolled back.
     * This ensures data consistency.
     */
    @Transactional
    public String processUserActivityAndUpdateMultipleUsers(Long userId1, Long userId2, String activityDetails) {
        Optional<User> user1Optional = userRepository.findById(userId1);
        Optional<User> user2Optional = userRepository.findById(userId2);

        if (user1Optional.isEmpty() || user2Optional.isEmpty()) {
            throw new IllegalArgumentException("One or both users not found for processing activity.");
        }

        User user1 = user1Optional.get();
        User user2 = user2Optional.get();

        System.out.println("Processing activity for user: " + user1.getUsername() + " and " + user2.getUsername());

        // Simulate complex business logic
        // E.g., record activity, update points, link accounts, etc.
        // For demonstration, let's modify their last names
        user1.setLastName(user1.getLastName() != null ? user1.getLastName() + "-Activity" : "Activity");
        user2.setLastName(user2.getLastName() != null ? user2.getLastName() + "-Related" : "Related");

        userRepository.save(user1);
        userRepository.save(user2);

        // Imagine a third operation that might fail
        // E.g., writing to a log, sending a notification, or another database operation
        // If an exception occurs here, both user saves above would be rolled back.
        // For example:
        // if (activityDetails.contains("error")) {
        //     throw new RuntimeException("Simulating a critical error during transaction processing.");
        // }

        System.out.println("User activity processed and users updated successfully.");
        return "Activity '" + activityDetails + "' processed for " + user1.getUsername() + " and " + user2.getUsername();
    }
}

